function LogoThumb({ num, size = 48 }) {
  return (
    <div style={{ width: size, height: size, borderRadius: size > 32 ? 8 : 6, overflow: "hidden", flexShrink: 0, boxShadow: "0 1px 4px rgba(0,0,0,0.1)" }}>
      <img src={L[`l${num}`]} alt={`Logo ${num}`} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
    </div>
  );
}

